What does this program print?

```cpp
#include <iostream>
int& larger(int& a, int& b) {
    return (a >= b) ? a : b;
}
int main() {
    int x { 3 }, y { 7 };
    larger(x, y) = 50;
    std::cout << x << ' ' << y << '\n';
    return 0;
}
```

