What does this program print?

```cpp
#include <iostream>
const int& smaller(const int& a, const int& b) {
    return (a <= b) ? a : b;
}
int main() {
    int p { 5 }, q { 2 };
    std::cout << smaller(p, q) << '\n';
    std::cout << smaller(q, p) << '\n';
    return 0;
}
```
